class Solution:
    def minAbsDifference(self, nums, goal):
        n = len(nums)
        best = abs(goal)
        for mask in range(1 << n):
            s = 0
            m = mask
            idx = 0
            while m:
                if m & 1:
                    s += nums[idx]
                m >>= 1
                idx += 1
            d = abs(s - goal)
            if d < best:
                best = d
                if best == 0:
                    return 0
        return best

