import bisect
class Solution:
    def minAbsDifference(self, nums, goal):
        n = len(nums)
        mid = n // 2
        left, right = nums[:mid], nums[mid:]

        def subset_sums(arr):
            sums = [0]
            for v in arr:
                sums += [x + v for x in sums]
            return sums

        ls = subset_sums(left)
        rs = sorted(subset_sums(right))
        best = float('inf')
        for x in ls:
            need = goal - x
            i = bisect.bisect_left(rs, need)
            for j in (i - 1, i):
                if 0 <= j < len(rs):
                    best = min(best, abs(x + rs[j] - goal))
        return best

