var minAbsDifference = function(nums, goal) {
    const n = nums.length;
    const mid = n >> 1;
    const left = nums.slice(0, mid), right = nums.slice(mid);
    const subsetSums = (arr) => {
        let sums = [0];
        for (const v of arr) {
            const next = [];
            for (const x of sums) next.push(x + v);
            sums = sums.concat(next);
        }
        return sums;
    };
    const ls = subsetSums(left);
    const rs = subsetSums(right).sort((a, b) => a - b);
    const lowerBound = (target) => {
        let lo = 0, hi = rs.length;
        while (lo < hi) {
            const m = (lo + hi) >> 1;
            if (rs[m] < target) lo = m + 1; else hi = m;
        }
        return lo;
    };
    let best = Infinity;
    for (const x of ls) {
        const need = goal - x;
        const i = lowerBound(need);
        for (const j of [i - 1, i]) {
            if (j >= 0 && j < rs.length) {
                best = Math.min(best, Math.abs(x + rs[j] - goal));
            }
        }
    }
    return best;
};
